import{_ as t,o as a,c as r,aQ as o}from"./chunks/framework.cDvftfeu.js";const u=JSON.parse('{"title":"Developers","description":"Overview of Ham developer projects and documentation.","frontmatter":{"description":"Overview of Ham developer projects and documentation.","next":{"text":"Ham Connect Overview","link":"/en/developers/open-platform/"}},"headers":[],"relativePath":"en/developers/index.md","filePath":"en/developers/index.md","lastUpdated":1777525243000}'),n={name:"en/developers/index.md"};function i(d,e,s,p,l,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /developers.md for this page in Markdown format</div><h1 id="developers" tabindex="-1">Developers <a class="header-anchor" href="#developers" aria-label="Permalink to &quot;Developers&quot;">​</a></h1><p>Welcome to the Ham developer documentation! Ham currently includes the following projects:</p><table tabindex="0"><thead><tr><th>Project</th><th>Description</th><th>Repository</th></tr></thead><tbody><tr><td><a href="/en/developers/open-platform/">Ham Connect</a></td><td>Open platform OAuth 2.0 authorization service</td><td>—</td></tr><tr><td><a href="/en/developers/ham-web/">Ham Web</a></td><td>Web frontend for SSO authorization and more</td><td><a href="https://github.com/whu-ham/ham-web" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td><a href="/en/developers/ham-rn/">Ham React Native Components</a></td><td>React Native component repository, integrated into native apps via OTA hot updates</td><td><a href="https://github.com/whu-ham/ham-rn" target="_blank" rel="noreferrer">GitHub</a></td></tr></tbody></table><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Ham Connect</strong> is the OAuth 2.0 authorization service provided by the Ham open platform, allowing third-party apps to securely obtain Ham user authorization and implement &quot;Sign in with Ham&quot; functionality.</p><p><strong>Ham Web</strong> is the web frontend for Ham, built with Next.js. It primarily serves the SSO single sign-on authorization flow (including QR code login and Passkey login) and acts as the web entry point for the Ham Connect platform.</p><p><strong>Ham React Native Components</strong> is the React Native component repository for the Ham app, integrated into native apps via OTA hot updates. It handles the UI and business logic for core features such as course schedule queries, grade queries, GPA calculation, and CAS authentication.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>Open-source projects are licensed under the <a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT License</a>. Community contributions are welcome. Please read each project&#39;s contributing guide before submitting a PR.</p>',10)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
